import requests
import json

# --- Configuration ---
RABBITMQ_HOST = 'localhost'
RABBITMQ_PORT = 15672
RABBITMQ_API_USERNAME = 'guest'  # Use an admin user for configuration
RABBITMQ_API_PASSWORD = 'guest'

BASE_URL = f'http://{RABBITMQ_HOST}:{RABBITMQ_PORT}/api'

# --- Tenant Definitions ---
# Each tenant will get a vhost, a user, and specific permissions
TENANTS = [
    {
        'name': 'tenant_alpha',
        'password': 'password_alpha',
        'permissions': {
            'configure': '.*', # Allow configuring all resources within the vhost
            'write': '.*',    # Allow writing to all resources within the vhost
            'read': '.*'      # Allow reading from all resources within the vhost
        }
    },
    {
        'name': 'tenant_beta',
        'password': 'password_beta',
        'permissions': {
            'configure': '^queue_beta_.*', # Only queues starting with queue_beta_
            'write': '^queue_beta_.*',
            'read': '^queue_beta_.*'
        }
    },
    {
        'name': 'tenant_gamma',
        'password': 'password_gamma',
        'permissions': {
            'configure': '^exchange_gamma_.*', # Only exchanges starting with exchange_gamma_
            'write': '^exchange_gamma_.*',
            'read': '^queue_gamma_.*' # Read from queues starting with queue_gamma_
        }
    }
]

# --- Helper Functions ---

def api_request(method, endpoint, data=None, expected_status=200):
    url = f"{BASE_URL}{endpoint}"
    headers = {'Content-Type': 'application/json'}
    auth = (RABBITMQ_API_USERNAME, RABBITMQ_API_PASSWORD)

    try:
        if method == 'GET':
            response = requests.get(url, auth=auth, headers=headers)
        elif method == 'PUT':
            response = requests.put(url, auth=auth, headers=headers, data=json.dumps(data))
        elif method == 'POST':
            response = requests.post(url, auth=auth, headers=headers, data=json.dumps(data))
        elif method == 'DELETE':
            response = requests.delete(url, auth=auth, headers=headers)
        else:
            raise ValueError(f"Unsupported HTTP method: {method}")

        response.raise_for_status() # Raise an exception for HTTP errors (4xx or 5xx)

        if response.status_code == expected_status:
            print(f"SUCCESS: {method} {url} -> Status {response.status_code}")
            return response.json() if response.content else None
        else:
            print(f"WARNING: {method} {url} -> Unexpected Status {response.status_code}. Expected {expected_status}")
            print(f"Response: {response.text}")
            return None

    except requests.exceptions.HTTPError as err:
        print(f"ERROR: HTTP Error during {method} {url}: {err}")
        print(f"Response Content: {err.response.text}")
        return None
    except requests.exceptions.ConnectionError as err:
        print(f"ERROR: Connection Error during {method} {url}: {err}")
        print(f"Please ensure RabbitMQ Management plugin is running at {RABBITMQ_HOST}:{RABBITMQ_PORT}")
        return None
    except Exception as err:
        print(f"ERROR: An unexpected error occurred during {method} {url}: {err}")
        return None

def create_vhost(vhost_name):
    print(f"\n--- Creating VHost: {vhost_name} ---")
    return api_request('PUT', f'/vhosts/{vhost_name}', expected_status=204) # 204 No Content for successful creation

def create_user(username, password):
    print(f"\n--- Creating User: {username} ---")
    data = {
        'password': password,
        'tags': 'management' # Optional: Add 'management' tag if user needs UI access
    }
    return api_request('PUT', f'/users/{username}', data=data, expected_status=204)

def set_permissions(vhost_name, username, configure_regex, write_regex, read_regex):
    print(f"\n--- Setting Permissions for User '{username}' on VHost '{vhost_name}' ---")
    data = {
        'configure': configure_regex,
        'write': write_regex,
        'read': read_regex
    }
    return api_request('PUT', f'/permissions/{vhost_name}/{username}', data=data, expected_status=204)

# --- Main Script ---

if __name__ == "__main__":
    print(f"Starting RabbitMQ Configuration Script for multi-tenant setup...")
    print(f"Connecting to RabbitMQ Management API at {BASE_URL}")

    # Verify API connectivity (optional, but good practice)
    if not api_request('GET', '/overview'):
        print("Failed to connect to RabbitMQ Management API. Exiting.")
        exit(1)

    for tenant in TENANTS:
        tenant_name = tenant['name']
        tenant_password = tenant['password']
        tenant_perms = tenant['permissions']

        # 1. Create Virtual Host
        create_vhost(tenant_name)

        # 2. Create User
        create_user(tenant_name, tenant_password)

        # 3. Set Permissions for the user on their specific vhost
        set_permissions(
            vhost_name=tenant_name,
            username=tenant_name,
            configure_regex=tenant_perms['configure'],
            write_regex=tenant_perms['write'],
            read_regex=tenant_perms['read']
        )
    
    print("\nRabbitMQ configuration script completed.")
    print("Please test connectivity for each tenant using their respective credentials.")